[{"location":"architecture/jobs/#architecture-jobs","page":"Jobs","title":"Jobs","text":"","category":"section"},{"location":"architecture/jobs/#Overview","page":"Jobs","title":"Overview","text":"","category":"section"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"Jobs represent the actual work to be performed in Gears. There are three types of jobs, each with different execution characteristics.","category":"page"},{"location":"architecture/jobs/#Job-Interface","page":"Jobs","title":"Job Interface","text":"","category":"section"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"All jobs implement the Job abstract type and must provide:","category":"page"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"progress!(job::Job, t::Quantity{<:Number, 𝐓})","category":"page"},{"location":"architecture/jobs/#Gears.progress!","page":"Jobs","title":"Gears.progress!","text":"progress!(ticker::Ticker, delta_time::Quantity{<:Number, 𝐓})\n\nProgress the ticker by a delta time, updating internal state accordingly.\n\n\n\n\n\nprogress!(job::Job, t::Quantity{<:Number, 𝐓})\n\nExecute the job with the current time. The job decides internally whether to perform work.\n\n\n\n\n\nprogress!(job::TimedJob, dt::Quantity{<:Number, 𝐓})\n\nProgress the job by the specified time delta, executing the function for each available tick.\n\n\n\n\n\n","category":"function"},{"location":"architecture/jobs/#Job-Types","page":"Jobs","title":"Job Types","text":"","category":"section"},{"location":"architecture/jobs/#TimedJob","page":"Jobs","title":"TimedJob","text":"","category":"section"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"Execute at regular intervals. Created with every(scheduler, interval).","category":"page"},{"location":"architecture/jobs/#AsapJob","page":"Jobs","title":"AsapJob","text":"","category":"section"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"Execute as soon as possible (highest priority). Created with every(scheduler, asap).","category":"page"},{"location":"architecture/jobs/#EventJob","page":"Jobs","title":"EventJob","text":"","category":"section"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"Execute when data arrives on a channel. Created with every(scheduler, channel).","category":"page"},{"location":"architecture/jobs/#Usage-Examples","page":"Jobs","title":"Usage Examples","text":"","category":"section"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"# Timed job - executes every 10ms\nevery(scheduler, 10ms) do dt\n    plan!(agent)\nend\n\n# ASAP job - executes as soon as possible\nevery(scheduler, asap) do\n    process_urgent_task()\nend\n\n# Event job - executes when data arrives\nevents = Channel{String}(Inf)\nevery(scheduler, events) do event\n    handle_event(event)\nend","category":"page"},{"location":"architecture/jobs/","page":"Jobs","title":"Jobs","text":"","category":"page"},{"location":"tutorials/#tutorials","page":"Overview","title":"Tutorials","text":"","category":"section"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"Welcome to the Gears tutorials! These tutorials will guide you through the core concepts step by step, building your understanding progressively.","category":"page"},{"location":"tutorials/#Tutorial-Order","page":"Overview","title":"Tutorial Order","text":"","category":"section"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"We recommend following these tutorials in order:","category":"page"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"Quick Start - Get up and running in 5 minutes\nBasic Scheduling - Learn the fundamentals of job scheduling\nClocks and Time - Understand time abstraction and control\nSchedulers - Configure and customize job execution\nJob Types - Explore different ways to trigger jobs\nThreading - Run jobs in parallel","category":"page"},{"location":"tutorials/#Prerequisites","page":"Overview","title":"Prerequisites","text":"","category":"section"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"Basic familiarity with Julia\nUnderstanding of functions and closures\nBasic knowledge of channels (for event-driven jobs)","category":"page"},{"location":"tutorials/#What-You'll-Learn","page":"Overview","title":"What You'll Learn","text":"","category":"section"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"By the end of these tutorials, you'll be able to:","category":"page"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"Schedule tasks at regular intervals\nHandle urgent tasks immediately\nRespond to events as they arrive\nControl time in simulations\nRun multiple jobs in parallel\nDebug timing issues","category":"page"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"Let's get started with the Quick Start!","category":"page"},{"location":"tutorials/","page":"Overview","title":"Overview","text":"","category":"page"},{"location":"architecture/c4_model/#architecture-c4-model","page":"C4 Model","title":"C4 Model","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"This page contains the complete C4 model for Gears, showing the architecture at all levels from system context down to detailed components.","category":"page"},{"location":"architecture/c4_model/#Level-1:-System-Context","page":"C4 Model","title":"Level 1: System Context","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"Gears sits at the heart of simulation systems, providing precise timing control for agent-environment interactions:","category":"page"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"C4Context\n    title System Context diagram for Gears\n\n    Person(developer, \"Simulation Developer\", \"Developers building agent-environment systems\")\n\n    System_Boundary(simulation, \"Simulation Environment\") {\n        System(envengine, \"Gears\", \"Precise timing control and job scheduling\")\n        System(agent, \"Agent System (RxInfer)\", \"Intelligent agents that plan and act\")\n        System(environment, \"Environment (User defined)\", \"Simulated world that agents interact with\")\n    }\n\n    Rel(developer, envengine, \"Uses\", \"every(), for_next() API\")\n    Rel(envengine, agent, \"Schedules\", \"Agent planning tasks\")\n    Rel(envengine, environment, \"Schedules\", \"Environment updates\")","category":"page"},{"location":"architecture/c4_model/#Level-2:-Container-Architecture","page":"C4 Model","title":"Level 2: Container Architecture","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"Gears is organized into several key containers, each with specific responsibilities:","category":"page"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"C4Container\n    title Container diagram for Gears\n\n    Person(developer, \"Simulation Developer\", \"Developers using Gears\")\n\n    Container_Boundary(envengine, \"Gears Package\") {\n        Container(api, \"Public API\", \"Julia Module\", \"every(), for_next(), update!() functions\")\n        Container(scheduler, \"Scheduler System\", \"Julia Module\", \"TickedScheduler and job coordination\")\n        Container(clock, \"Clock System\", \"Julia Module\", \"MachineClock, VirtualClock time abstraction\")\n        Container(jobs, \"Job System\", \"Julia Module\", \"TimedJob, AsapJob, EventJob implementations\")\n        Container(utils, \"Utilities\", \"Julia Module\", \"Ticker, singletons, error handling\")\n    }\n\n    Rel(developer, api, \"Calls\", \"Julia functions\")\n    Rel(api, scheduler, \"Uses\", \"Schedules jobs\")\n    Rel(scheduler, clock, \"Queries\", \"Current time\")\n    Rel(scheduler, jobs, \"Executes\", \"Job progress\")","category":"page"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"This level shows the main modules within Gears and how they interact. The Public API is the entry point, while the Scheduler coordinates between the Clock System and Job System.","category":"page"},{"location":"architecture/c4_model/#Level-3:-Component-Architecture","page":"C4 Model","title":"Level 3: Component Architecture","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"The detailed component view shows how the different parts of Gears interact:","category":"page"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"C4Component\n    title Component diagram for Gears\n\n    Container_Boundary(envengine, \"Gears Package\") {\n        Container_Boundary(api, \"Public API\") {\n            Component(every_function, \"every()\", \"Julia Function\", \"Job creation function\")\n            Component(for_next_function, \"for_next()\", \"Julia Function\", \"Time loop function\")\n            Component(update_function, \"update!()\", \"Julia Function\", \"Scheduler update function\")\n        }\n        \n        Container_Boundary(scheduler, \"Scheduler System\") {\n            Component(ticked_scheduler, \"TickedScheduler\", \"Julia Type\", \"Main scheduler implementation\")\n            Component(scheduler_interface, \"Scheduler Interface\", \"Abstract Type\", \"schedule!(), update!() contracts\")\n        }\n        \n        Container_Boundary(clock, \"Clock System\") {\n            Component(machine_clock, \"MachineClock\", \"Julia Type\", \"System time clock\")\n            Component(virtual_clock, \"VirtualClock\", \"Julia Type\", \"Controllable simulation clock\")\n            Component(clock_interface, \"Clock Interface\", \"Abstract Type\", \"now() method contract\")\n        }\n        \n        Container_Boundary(jobs, \"Job System\") {\n            Component(timed_job, \"TimedJob\", \"Julia Type\", \"Periodic execution jobs\")\n            Component(event_job, \"EventJob\", \"Julia Type\", \"Event-driven jobs\")\n            Component(asap_job, \"AsapJob\", \"Julia Type\", \"As-soon-as-possible jobs\")\n            Component(job_interface, \"Job Interface\", \"Abstract Type\", \"progress!() method contract\")\n        }\n        \n        Container_Boundary(utils, \"Utilities\") {\n            Component(ticker, \"Ticker\", \"Julia Type\", \"Time accumulation and tick processing\")\n            Component(singletons, \"Global Singletons\", \"Julia Module\", \"Global state management\")\n            Component(errors, \"Error Handling\", \"Julia Module\", \"NotImplementedError and custom exceptions\")\n        }\n    }\n\n    Rel(every_function, scheduler_interface, \"Creates jobs via\", \"schedule!()\")\n    Rel(update_function, scheduler_interface, \"Calls\", \"update!()\")\n    \n    Rel(ticked_scheduler, clock_interface, \"Queries time\", \"now()\")\n    Rel(ticked_scheduler, job_interface, \"Executes\", \"progress!()\")\n    Rel(ticked_scheduler, ticker, \"Uses\", \"Scheduler timing\")\n    Rel(ticked_scheduler, scheduler_interface, \"Implements\")\n    \n    Rel(machine_clock, clock_interface, \"Implements\")\n    Rel(virtual_clock, clock_interface, \"Implements\")\n    \n    Rel(timed_job, job_interface, \"Implements\")\n    Rel(timed_job, ticker, \"Uses\", \"Job timing\")\n    Rel(asap_job, job_interface, \"Implements\")\n    Rel(event_job, job_interface, \"Implements\")\n\n    Rel(for_next_function, clock_interface, \"Takes as argument\", \"Which clock for timekeeping\")","category":"page"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"This level shows the detailed components within each container. The TickedScheduler is the core component that coordinates between clocks and jobs, while the Ticker utility provides shared timing functionality.","category":"page"},{"location":"architecture/c4_model/#Key-Relationships","page":"C4 Model","title":"Key Relationships","text":"","category":"section"},{"location":"architecture/c4_model/#System-Context-Level","page":"C4 Model","title":"System Context Level","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"Simulation Developers use Gears's simple API (every(), for_next()) to schedule tasks\nGears coordinates timing between agent planning and environment updates, enabling complex simulation scenarios","category":"page"},{"location":"architecture/c4_model/#Container-Level","page":"C4 Model","title":"Container Level","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"Public API provides the main interface for users\nScheduler System manages job execution and timing coordination\nClock System provides time abstraction with machine and virtual clocks\nJob System defines different types of executable tasks\nUtilities handle shared components like Ticker and global state management","category":"page"},{"location":"architecture/c4_model/#Component-Level","page":"C4 Model","title":"Component Level","text":"","category":"section"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"TickedScheduler coordinates between clocks and jobs, calling progress!() on jobs at appropriate times\nTicker provides shared timing functionality used by both schedulers and timed jobs\nInterface components define contracts that concrete implementations must follow\nGlobal singletons provide default instances for simple use cases (though explicit instances are recommended)","category":"page"},{"location":"architecture/c4_model/","page":"C4 Model","title":"C4 Model","text":"","category":"page"},{"location":"architecture/#architecture","page":"Overview","title":"Architecture Overview","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Gears is designed around three core abstractions that work together to provide flexible task scheduling in simulation environments:","category":"page"},{"location":"architecture/#Core-Concepts","page":"Overview","title":"Core Concepts","text":"","category":"section"},{"location":"architecture/#1.-**Clocks**-Time-Abstraction","page":"Overview","title":"1. Clocks - Time Abstraction","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Clocks provide a unified interface for time, allowing you to work with either real system time or controllable virtual time for simulations.","category":"page"},{"location":"architecture/#2.-**Jobs**-Task-Definitions","page":"Overview","title":"2. Jobs - Task Definitions","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Jobs represent the actual work to be performed. There are three types:","category":"page"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Timed Jobs: Execute at regular intervals (e.g., every 10ms)\nASAP Jobs: Execute as soon as possible (highest priority)\nEvent Jobs: Execute when data arrives on a channel","category":"page"},{"location":"architecture/#3.-**Schedulers**-Job-Coordination","page":"Overview","title":"3. Schedulers - Job Coordination","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Schedulers manage when jobs should be executed, coordinating between the clock and the jobs. Schedulers can be configured to run in a single thread or in multiple threads.","category":"page"},{"location":"architecture/#Main-Entry-Points","page":"Overview","title":"Main Entry Points","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"The primary way users interact with Gears is through the every() function, which creates different types of jobs:","category":"page"},{"location":"architecture/#Job-Types","page":"Overview","title":"Job Types","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Timed Jobs - Execute at regular intervals\nevery(10ms) do dt\n    plan!(agent)\nend\nASAP Jobs - Execute as soon as possible (highest priority)\nevery(asap) do\n    process_urgent_task()\nend\nEvent Jobs - Execute when data arrives on a channel\nevents = Channel{String}(Inf)\nevery(events) do event\n    handle_event(event)\nend","category":"page"},{"location":"architecture/#Scheduler-Control","page":"Overview","title":"Scheduler Control","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"every(scheduler,interval) - Schedule tasks\nfor_next(clock, duration) - Run the scheduler for a specific time period\nupdate!(scheduler) - Update the scheduler with the current time and execute all jobs that are scheduled to run within this time period","category":"page"},{"location":"architecture/#Example-Usage","page":"Overview","title":"Example Usage","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"clock = MachineClock()\nscheduler = TickedScheduler(clock, 1.0ms)\n\n# Schedule agent planning every 10ms\nevery(scheduler,10ms) do dt\n    plan!(agent)\nend\n\n# Schedule environment updates every 1ms  \nevery(scheduler,1ms) do dt\n    update!(environment)\nend\n\n# Handle urgent tasks as soon as possible\nevery(scheduler,asap) do\n    process_urgent_events()\nend\n\n# Run the simulation for 5 seconds\nfor_next(clock, 5s) do\n    update!(scheduler)  # Process all scheduled jobs\nend","category":"page"},{"location":"architecture/","page":"Overview","title":"Overview","text":"This creates an asynchronous agent-environment interaction loop where both components run at their own frequencies, with urgent tasks handled immediately, all coordinated by the scheduler.","category":"page"},{"location":"architecture/#Architecture-Principles","page":"Overview","title":"Architecture Principles","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"Virtual Time First: All scheduling operates in virtual time, which can optionally sync with real time\nJob Autonomy: Jobs decide when to execute based on their own logic when invoked by the scheduler\nScheduler Coordination: The scheduler coordinates between clocks and jobs, calling progress!() on jobs at appropriate times\nMultiple Dispatch: Different job types and schedulers can have specialized behaviors through Julia's multiple dispatch system","category":"page"},{"location":"architecture/#Documentation-Structure","page":"Overview","title":"Documentation Structure","text":"","category":"section"},{"location":"architecture/","page":"Overview","title":"Overview","text":"C4 Model - Complete C4 model showing all architecture levels\nClocks - Detailed documentation on clock implementations\nSchedulers - Detailed documentation on scheduler implementations  \nJobs - Detailed documentation on job types and implementations","category":"page"},{"location":"architecture/","page":"Overview","title":"Overview","text":"","category":"page"},{"location":"user_guide/#user-guide","page":"Overview","title":"User Guide","text":"","category":"section"},{"location":"user_guide/","page":"Overview","title":"Overview","text":"Welcome to the Gears User Guide! This section provides comprehensive reference documentation for all features and APIs.","category":"page"},{"location":"user_guide/#Quick-Navigation","page":"Overview","title":"Quick Navigation","text":"","category":"section"},{"location":"user_guide/","page":"Overview","title":"Overview","text":"API Reference - Complete function and type documentation\nSharp Bits - Learn about sharp bits","category":"page"},{"location":"user_guide/","page":"Overview","title":"Overview","text":"","category":"page"},{"location":"architecture/schedulers/#architecture-schedulers","page":"Schedulers","title":"Schedulers","text":"","category":"section"},{"location":"architecture/schedulers/#Overview","page":"Schedulers","title":"Overview","text":"","category":"section"},{"location":"architecture/schedulers/","page":"Schedulers","title":"Schedulers","text":"Schedulers distribute time to jobs and manage when jobs should be executed, coordinating between the clock and the jobs. They can be configured to run in a single thread or in multiple threads.","category":"page"},{"location":"architecture/schedulers/#Scheduler-Interface","page":"Schedulers","title":"Scheduler Interface","text":"","category":"section"},{"location":"architecture/schedulers/","page":"Schedulers","title":"Schedulers","text":"All schedulers implement the Scheduler abstract type and must provide:","category":"page"},{"location":"architecture/schedulers/","page":"Schedulers","title":"Schedulers","text":"schedule!(scheduler::Scheduler, job::Job)\nupdate!(scheduler::Scheduler)","category":"page"},{"location":"architecture/schedulers/#Gears.schedule!","page":"Schedulers","title":"Gears.schedule!","text":"schedule!(scheduler::Scheduler, job::Job)\n\nRegister a job with the scheduler to run. Can be implemented for concrete types to define scheduling behavior for different schedulers and job types.\n\n\n\n\n\nschedule!(scheduler::TickedScheduler, job::Job)\n\nSchedule a job to be executed by the scheduler.\n\n\n\n\n\n","category":"function"},{"location":"architecture/schedulers/#Gears.update!","page":"Schedulers","title":"Gears.update!","text":"update!(scheduler::Scheduler)\n\nUpdate the scheduler to the current time as provided with the associated clock. This distributes time to the scheduled jobs until virtual time has caught up with the current time provided by the clock (optionally also virtual).\n\n\n\n\n\nupdate!(scheduler::TickedScheduler)\n\nUpdate the scheduler by advancing to the current time and processing available ticks.\n\n\n\n\n\n","category":"function"},{"location":"architecture/schedulers/#Implementations","page":"Schedulers","title":"Implementations","text":"","category":"section"},{"location":"architecture/schedulers/#TickedScheduler","page":"Schedulers","title":"TickedScheduler","text":"","category":"section"},{"location":"architecture/schedulers/","page":"Schedulers","title":"Schedulers","text":"Discretizes time into ticks and executes jobs within each tick. Provides deterministic execution timing.","category":"page"},{"location":"architecture/schedulers/#Usage-Examples","page":"Schedulers","title":"Usage Examples","text":"","category":"section"},{"location":"architecture/schedulers/","page":"Schedulers","title":"Schedulers","text":"clock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms)\n\n# Schedule jobs\nevery(scheduler, 30ms) do dt\n    println(\"Timed job: $(now(clock))\")\nend\n\n# Run scheduler\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"architecture/schedulers/","page":"Schedulers","title":"Schedulers","text":"","category":"page"},{"location":"tutorials/schedulers/#tutorial-schedulers","page":"Schedulers","title":"Schedulers","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Schedulers are the core component that coordinates between a clock and a collection of jobs. This tutorial covers how to configure and customize schedulers for different use cases.","category":"page"},{"location":"tutorials/schedulers/#What-Are-Schedulers?","page":"Schedulers","title":"What Are Schedulers?","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Schedulers manage when jobs should be executed by:","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Tracking the current time from a clock\nDetermining which jobs are due for execution\nExecuting jobs in the correct order","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Schedulers are used to orchestrate the execution of jobs in a simulation, and they can be passed to the every() function.","category":"page"},{"location":"tutorials/schedulers/#Default-Scheduler","page":"Schedulers","title":"Default Scheduler","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"When you use every() without specifying a scheduler, Gears uses a default scheduler with the global clock:","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"# Uses default scheduler with global clock\nevery(100ms) do dt\n    println(\"Using default scheduler\")\nend","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"However, we recommend passing a scheduler to the every() function to get more control over the execution of jobs.","category":"page"},{"location":"tutorials/schedulers/#TickedScheduler","page":"Schedulers","title":"TickedScheduler","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"The TickedScheduler is the main scheduler implementation. It divides time into discrete ticks and executes all jobs that are due within each tick. This is based on the Game Loop Pattern. The TickedScheduler takes a Clock and a tick rate. The Clock will be used as an abstract timekeeper, and the tick rate will be used to discretize time.","category":"page"},{"location":"tutorials/schedulers/#Gears.TickedScheduler-tutorials-schedulers","page":"Schedulers","title":"Gears.TickedScheduler","text":"TickedScheduler{C <: Clock, T} <: Scheduler\n\nA scheduler that processes jobs at regular tick intervals.\n\nFields\n\nclock::C: The clock providing time information\njobs::Vector{Job}: The jobs to be scheduled\nticker::Ticker{T}: The ticker that manages timing\n\n\n\n\n\n","category":"type"},{"location":"tutorials/schedulers/#Basic-TickedScheduler","page":"Schedulers","title":"Basic TickedScheduler","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"A TickedScheduler can be created by associating a clock and a time interval between ticks. Then, a scheduler is passed to the every() function to schedule jobs on that scheduler, and we can use for_next(clock, duration) to run the simulation for a specific duration, given the clock.","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"using Gears\n\nclock = VirtualClock()\n\n# Create scheduler with 10ms tick rate\nscheduler = TickedScheduler(clock, 10ms)\n\n# Schedule jobs using the custom scheduler\nevery(scheduler, 50ms) do dt\n    println(\"Job executed at $(now(clock))\")\nend\n\n# Run the scheduler\nfor_next(clock, 200ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"tutorials/schedulers/#Tick-Rate-Selection","page":"Schedulers","title":"Tick Rate Selection","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"The tick rate determines how often the scheduler checks for jobs to execute. Let's take a look at the following three examples:","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"# Create a clock\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 1ms)\n\nevery(scheduler, 5ms) do dt\n    println(\"Job executed at $(now(clock))\")\n    println(\"dt: $dt\")\nend\n\nfor_next(clock, 30ms) do\n    update!(scheduler)\n    advance_time!(clock, 1ms)\nend","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Here, we see that the job is executed at 5ms intervals. Time is discretized in 1ms increments. Let's see what happens if the tick rate is 10ms instead of 1ms.","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"clock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms)\n\nevery(scheduler, 5ms) do dt\n    println(\"Job executed at $(now(clock))\")\n    println(\"dt: $dt\")\nend\n\nfor_next(clock, 30ms) do\n    update!(scheduler)\n    advance_time!(clock, 1ms)\nend","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Now, we see that jobs are executed twice at 10ms intervals. This is because the TickedScheduler ticks whenever the current time modulo 10ms is zero, meaning that at time 10ms, the job is executed twice. Note that dt for these calls is still 5ms. The scheduler behavior therefore only determines the order in which jobs are executed, but not the internal interval that the job uses. This enforces deterministic behavior in the job execution, allowing reproducible simulations. In general, it is advised to take a ticking frequency that is higher than the job intervals, in order to match the true resolution as closely as possible.","category":"page"},{"location":"tutorials/schedulers/#Scheduler-Configuration","page":"Schedulers","title":"Scheduler Configuration","text":"","category":"section"},{"location":"tutorials/schedulers/#Threading-Support","page":"Schedulers","title":"Threading Support","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Enable multi-threading for parallel job execution:","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"# Single-threaded (default)\nscheduler = TickedScheduler(clock, 10ms)\n\n# Multi-threaded\nscheduler = TickedScheduler(clock, 10ms; threading=true);","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"The TickedScheduler supports multi-threading, and the threading keyword argument can be used to enable it. More details on threading can be found in the Threading tutorial.","category":"page"},{"location":"tutorials/schedulers/#Next-Steps","page":"Schedulers","title":"Next Steps","text":"","category":"section"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Now that you understand schedulers, explore:","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"Job Types - Explore different job triggers\nThreading - Run jobs in parallel\nUser Guide - Complete reference documentation","category":"page"},{"location":"tutorials/schedulers/","page":"Schedulers","title":"Schedulers","text":"","category":"page"},{"location":"tutorials/job_types/#tutorial-job-types","page":"Job Types","title":"Job Types","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Jobs represent the actual work to be performed in Gears. They are the atomic building blocks created with the every() function. On this page we will cover the creation of different types of jobs.","category":"page"},{"location":"tutorials/job_types/#Job-Types-Overview","page":"Job Types","title":"Job Types Overview","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Currently, Gears supports the following job types:","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Timed Jobs - Execute at regular intervals\nASAP Jobs - Execute as soon as possible (on every tick)\nEvent Jobs - Execute when data arrives on a channel","category":"page"},{"location":"tutorials/job_types/#Timed-Jobs","page":"Job Types","title":"Timed Jobs","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Timed jobs execute at regular intervals. They're perfect for periodic tasks like sensor readings, data collection or environment updates.","category":"page"},{"location":"tutorials/job_types/#Basic-Timed-Jobs","page":"Job Types","title":"Basic Timed Jobs","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"using Gears\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms)\n\n# Execute every 100 milliseconds\nevery(scheduler, 100ms) do dt\n    println(\"Timed job executed\")\nend","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Timed jobs require the dt parameter to be passed to the job body. This parameter represents the time interval between executions. It is also possible to pass a function to the every() function directly:","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"function timed_job(dt)\n    println(\"Timed job executed\")\nend\n\nevery(timed_job, scheduler, 100ms)","category":"page"},{"location":"tutorials/job_types/#ASAP-Jobs","page":"Job Types","title":"ASAP Jobs","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"ASAP (As Soon As Possible) jobs run whenever the scheduler ticks. They're perfect for tasks that need to be executed as often as possible.","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"note: Note\nThis behavior of AsapJob is different than desired. Ideally we would want an AsapJob to fire whenever it is not already running (e.g. start planning as soon as the previous planning is finished). This functionality is significantly more challenging, and more info can be found in the Sharp Bits section.","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"ASAP jobs do not require any additional arguments to be passed to the job body, and can be created by passing the asap constant to the every() function.","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"# Execute as soon as possible\nevery(scheduler, asap) do\n    println(\"ASAP job executedj\")\nend","category":"page"},{"location":"tutorials/job_types/#Event-Jobs","page":"Job Types","title":"Event Jobs","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Event jobs execute when data arrives on a Channel. They're perfect for reactive programming and handling asynchronous events.","category":"page"},{"location":"tutorials/job_types/#Basic-Event-Jobs","page":"Job Types","title":"Basic Event Jobs","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"# Create a channel for events\nevents = Channel{String}(Inf)\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms)\n\n# Schedule job to run when events arrive\nevery(scheduler, events) do event\n    println(\"Event processed at $(now(clock)): $event\")\nend\n\n# Send some events\nput!(events, \"Hello\")\nput!(events, \"World\")\nadvance_time!(clock, 10ms)\nupdate!(scheduler)","category":"page"},{"location":"tutorials/job_types/#Combining-Job-Types","page":"Job Types","title":"Combining Job Types","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"You can mix different job types in the same application:","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"using Gears\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms)\n\n# Create channels for different event types\nsensor_data = Channel{Float64}(Inf)\nalerts = Channel{String}(Inf)\n\n# Timed job: Read sensor every 50ms\nevery(scheduler, 50ms) do dt\n    reading = rand() * 100\n    put!(sensor_data, reading)\nend\n\n# Event job: Process sensor data\nevery(scheduler, sensor_data) do data\n    if data > 80\n        put!(alerts, \"High reading: $data\")\n    end\nend\n\n# Event job: Handle alerts\nevery(scheduler, alerts) do alert\n    println(\"ALERT: $alert\")\nend\n\n# ASAP job: Check for a condition\nevery(scheduler, asap) do\n    if rand() < 0.1\n        println(\"Low random number detected!\")\n    end\nend\n\n# Run the system\nfor_next(clock, 1s) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"tutorials/job_types/#Common-Pattern","page":"Job Types","title":"Common Pattern","text":"","category":"section"},{"location":"tutorials/job_types/#Producer-Consumer-Pattern","page":"Job Types","title":"Producer-Consumer Pattern","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"# Producer: Generate data\nevery(50ms) do dt\n    data = generate_data()\n    put!(data_channel, data)\nend\n\n# Consumer: Process data\nevery(data_channel) do data\n    process_data(data)\nend","category":"page"},{"location":"tutorials/job_types/#Next-Steps","page":"Job Types","title":"Next Steps","text":"","category":"section"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Now that you understand the different job types, learn about:","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"Threading - Run jobs in parallel","category":"page"},{"location":"tutorials/job_types/","page":"Job Types","title":"Job Types","text":"","category":"page"},{"location":"user_guide/sharp_bits/#user-guide-sharp-bits","page":"Sharp Bits","title":"Sharp Bits","text":"","category":"section"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"This section covers some of the work in progress in Gears.","category":"page"},{"location":"user_guide/sharp_bits/#Job-timing","page":"Sharp Bits","title":"Job timing","text":"","category":"section"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"Let's look at the following pseudocode:","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"using Gears\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 1ms)\n\n\nevery(scheduler, 50ms) do dt\n    new_plan = plan(agent)\n    wait(scheduler, 10ms)\n    change_plan!(agent, new_plan)\nend\n\nevery(scheduler, 5ms) do dt\n    send_action!(agent, environment)\nend\n\nevery(scheduler, 3ms) do dt\n    update!(environment)\nend\n\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"Let's see at what this code is executing, and then let's look at what we would want it to execute. At time 0ms, all 3 jobs are due and are scheduled. The scheduler will execute the jobs in the order they are scheduled, so the agent will start making a plan. This will take some time, and the next job is called which will send an action to the environment. However, the virtual time is still at 0ms, so, in a realistic environment, the plan that was just made by the agent would not have been available yet. The plan, in a sense, is fetched from the virtual future. Since we do not know (and can not know in advance) how long the planning would take, we have no way of knowing when the actual plan would have become available. ","category":"page"},{"location":"user_guide/sharp_bits/#ASAP-jobs-and-threading","page":"Sharp Bits","title":"ASAP jobs and threading","text":"","category":"section"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"Currently, when we are multithreading, the scheduler will wait until all jobs within a tick have been completed before advancing to the next tick. Let's look at the following code:","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"using Gears\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 1ms)\n\nevery(scheduler, asap) do\n    plan!(agent)\nend\n\nevery(scheduler, 10ms) do dt\n    send_action!(agent, environment)\nend\n\nevery(scheduler, 3ms) do dt\n    update!(environment)\nend\n\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"With this syntax, the user implies that plan! might take some time to complete, and we would just want to run it as soon as computational resources become available. However, with threading enabled, the scheduler will wait until all jobs within a tick have been completed before advancing to the next tick. This means that the plan! job will be executed at every tick, since the scheduler waits for the plan! job to complete before advancing to the next tick.","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"While this is a problem in threading, for single threaded execution, the problem is even worse. Since we only have 1 thread, all computational resources available will be dedicated to the plan! job, meaning that it will always have finished at the end of the tick, and will always be scheduled at the next tick.","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"We could solve this with a blocking keyword to the every() function, which would determine if the scheduler waits for a certain job to complete before advancing to the next tick. While this would solve the problem for multithreading, ensuring thread-safety would be a significant challenge, and still would not solve the problem for single threaded execution.","category":"page"},{"location":"user_guide/sharp_bits/#Job-ordering","page":"Sharp Bits","title":"Job ordering","text":"","category":"section"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"Currently, the scheduler will execute the jobs in the order they are scheduled. This means that, for the following code:","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"using Gears\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 1ms)\n\nevents = Channel{String}(Inf)\nevery(scheduler, events) do event\n    println(\"Event received at $(now(clock))\")\nend\n\nevery(scheduler, 10ms) do dt\n    push!(events, \"event\")\nend\n\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"and the following code:","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"using Gears\n\nclock = VirtualClock()\nscheduler = TickedScheduler(clock, 1ms)\n\nevents = Channel{String}(Inf)\n\nevery(scheduler, 10ms) do dt\n    push!(events, \"event\")\nend\n\n\nevery(scheduler, events) do event\n    println(\"Event received at $(now(clock))\")\nend\n\n\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"the behavior is different. This is because the scheduler will execute all jobs scheduled within the same tick in the order in which they are defined. This means that, for the first code, first the every(scheduler, events) job will check if there is any new data in events, and afterwards the every(scheduler, 10ms) job will push a new event to events, which will then be processed in the next tick. In the second code, first the every(scheduler, 10ms) job will push a new event to events, after which the every(scheduler, events) job will check if there is any new data in events, which at this point there is, so the event will be consumed within the same tick as it is being pushed.","category":"page"},{"location":"user_guide/sharp_bits/","page":"Sharp Bits","title":"Sharp Bits","text":"","category":"page"},{"location":"tutorials/threading/#tutorial-threading","page":"Threading","title":"Threading","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Learn how to run jobs in parallel using Gears's threading capabilities. This tutorial covers when and how to use multi-threading effectively.","category":"page"},{"location":"tutorials/threading/#Threading-Overview","page":"Threading","title":"Threading Overview","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Gears supports running jobs in multiple threads, allowing you to:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Execute multiple jobs simultaneously\nImprove performance for CPU-intensive tasks\nHandle concurrent operations efficiently","category":"page"},{"location":"tutorials/threading/#Enabling-Threading","page":"Threading","title":"Enabling Threading","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Threading is enabled by passing the threading=true keyword argument to the TickedScheduler constructor.","category":"page"},{"location":"tutorials/threading/#Basic-Threading-Setup","page":"Threading","title":"Basic Threading Setup","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"using Gears\n\nclock = VirtualClock()\n\n# Enable threading in the scheduler\nscheduler = TickedScheduler(clock, 10ms; threading=true)\n\n# Schedule jobs - they can now run in parallel\nevery(scheduler, 50ms) do dt\n    println(\"Job 1 at $(now(clock))\")\nend\n\nevery(scheduler, 50ms) do dt\n    println(\"Job 2 at $(now(clock))\")\nend\n\n# Run the threaded scheduler\nfor_next(clock, 200ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"tutorials/threading/#Threading-Behavior","page":"Threading","title":"Threading Behavior","text":"","category":"section"},{"location":"tutorials/threading/#Job-Execution-Model","page":"Threading","title":"Job Execution Model","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"With threading enabled:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Jobs scheduled for the same tick can run in parallel\nAll jobs for a tick must complete before the next tick starts\nThis prevents race conditions between ticks","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"scheduler = TickedScheduler(clock, 10ms; threading=true)\n\n# These jobs can run in parallel within the same tick\nevery(scheduler, 20ms) do dt\n    println(\"Job A at $(now(clock))\")\n    sleep(0.005)  # Simulate work\nend\n\nevery(scheduler, 20ms) do dt\n    println(\"Job B at $(now(clock))\")\n    sleep(0.005)  # Simulate work\nend","category":"page"},{"location":"tutorials/threading/#Thread-Safety","page":"Threading","title":"Thread Safety","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Thread safety is a highly complex topic, hence we will repeat the same warning as is in the Julia documentation:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"danger: Data Race Safety is Your Responsibility\nYou are entirely responsible for ensuring that your program is data-race free, and nothing promised here can be assumed if you do not observe that requirement. The observed results may be highly unintuitive.If data-races are introduced, Julia is not memory safe. Be very careful about reading any data if another thread might write to it, as it could result in segmentation faults or worse.","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"When accessing a mutable state from multiple jobs, it is the user's responsibility to ensure that the state is thread-safe and ensure and appropriate locking mechanism is used.","category":"page"},{"location":"tutorials/threading/#Unsafe-Patterns","page":"Threading","title":"Unsafe Patterns","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Shared mutable state:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"clock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms; threading=true)\n\n# Unsafe: Multiple threads modifying shared state\nshared_counter = Ref(0)\nsecond_shared_counter = Ref(0)\n\nevery(scheduler, 10ms) do dt\n    shared_counter[] += 1  # First access to mutable state\nend\n\nevery(scheduler, 10ms) do dt\n    second_shared_counter[] += shared_counter[]  # Race condition! Second access to mutable state\nend\n\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend\nprintln(\"shared_counter: $(shared_counter[])\")\nprintln(\"second_shared_counter: $(second_shared_counter[])\")","category":"page"},{"location":"tutorials/threading/#Safe-Patterns","page":"Threading","title":"Safe Patterns","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Obtain lock before accessing shared state:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"clock = VirtualClock()\nscheduler = TickedScheduler(clock, 10ms; threading=true)\nlck = ReentrantLock()\n\n\n# Unsafe: Multiple threads modifying shared state\nshared_counter = Ref(0)\nsecond_shared_counter = Ref(0)\n\nevery(scheduler, 10ms) do dt\n    lock(lck) do\n        shared_counter[] += 1  # First access to mutable state\n    end\nend\n\nevery(scheduler, 10ms) do dt\n    lock(lck) do\n        second_shared_counter[] += shared_counter[]  # Race condition! Second access to mutable state\n    end\nend\n\nfor_next(clock, 100ms) do\n    update!(scheduler)\n    advance_time!(clock, 10ms)\nend\nprintln(\"shared_counter: $(shared_counter[])\")\nprintln(\"second_shared_counter: $(second_shared_counter[])\")","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Read-only access:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"scheduler = TickedScheduler(clock, 10ms; threading=true)\n\n# Safe: Multiple threads can read the same data\nevery(scheduler, 50ms) do dt\n    value = read_configuration()\n    use_value(value)\nend","category":"page"},{"location":"tutorials/threading/#Performance-Considerations","page":"Threading","title":"Performance Considerations","text":"","category":"section"},{"location":"tutorials/threading/#Threading-Overhead","page":"Threading","title":"Threading Overhead","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Threading has overhead, so it's only beneficial when:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Jobs are CPU-intensive\nMultiple jobs run simultaneously\nThe work outweighs the threading overhead","category":"page"},{"location":"tutorials/threading/#Next-Steps","page":"Threading","title":"Next Steps","text":"","category":"section"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"Congratulations! You have completed the tutorial series for Gears. In order to get more information, you can:","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"API Reference - Complete function and type documentation\nSharp Bits - Learn about sharp bits","category":"page"},{"location":"tutorials/threading/","page":"Threading","title":"Threading","text":"","category":"page"},{"location":"architecture/clocks/#architecture-clocks","page":"Clocks","title":"Clocks","text":"","category":"section"},{"location":"architecture/clocks/#Overview","page":"Clocks","title":"Overview","text":"","category":"section"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"Clocks provide a unified interface for time abstraction in Gears. They allow you to work with either real system time or controllable virtual time for simulations.","category":"page"},{"location":"architecture/clocks/#Clock-Interface","page":"Clocks","title":"Clock Interface","text":"","category":"section"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"All clocks implement the Clock abstract type and must provide:","category":"page"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"now(clock::Clock) -> Quantity{<:Number, 𝐓}","category":"page"},{"location":"architecture/clocks/#Implementations","page":"Clocks","title":"Implementations","text":"","category":"section"},{"location":"architecture/clocks/#MachineClock","page":"Clocks","title":"MachineClock","text":"","category":"section"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"Uses system time for real-time simulations.","category":"page"},{"location":"architecture/clocks/#Gears.MachineClock-architecture-clocks","page":"Clocks","title":"Gears.MachineClock","text":"MachineClock\n\nA clock that uses the system time. The time is represented in seconds. Supports pausing and resuming to decouple logical time from system time. The start_time, pause_start_time, and total_paused_time are all represented in seconds and are wall clock (unstretched) time. Whenever now is called, the time is stretched by the stretch_factor. This means that when the stretch_factor is greater than 1, the time will progress faster than the wall clock time.\n\nFields\n\nstart_time::T: The system time when the clock was created or last reset\npaused::Bool: Whether the clock is currently paused\ntotal_paused_time::T: Cumulative time spent paused\npause_start_time::Union{T, Nothing}: System time when current pause started (if any)\nstretch_factor::F: The factor by which to stretch the time\n\n\n\n\n\n","category":"type"},{"location":"architecture/clocks/#VirtualClock","page":"Clocks","title":"VirtualClock","text":"","category":"section"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"Controllable time for deterministic simulations.","category":"page"},{"location":"architecture/clocks/#Gears.VirtualClock-architecture-clocks","page":"Clocks","title":"Gears.VirtualClock","text":"VirtualClock\n\nA clock that uses virtual time for simulations. The time is represented in seconds.\n\nFields\n\ncurrent_time::T: The current time of the clock\n\nThis clock can be advanced with the advance_time! function.\n\n\n\n\n\n","category":"type"},{"location":"architecture/clocks/#Usage-Examples","page":"Clocks","title":"Usage Examples","text":"","category":"section"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"using Gears\n\n\n# Real-time clock\nclock = MachineClock()\nprintln(now(clock))  # Machine clock starts paused\n\n# Virtual clock for simulations\nclock = VirtualClock()\nadvance_time!(clock, 50ms)\nprintln(now(clock))  # 0.05 s","category":"page"},{"location":"architecture/clocks/","page":"Clocks","title":"Clocks","text":"","category":"page"},{"location":"quickstart/#quickstart","page":"Quick Start","title":"Quick Start","text":"","category":"section"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"Get Gears running in under 5 minutes! This tutorial shows you the simplest way to schedule and execute jobs.","category":"page"},{"location":"quickstart/#Installation","page":"Quick Start","title":"Installation","text":"","category":"section"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"using Pkg\nPkg.add(\"Gears\")","category":"page"},{"location":"quickstart/#Your-First-Scheduled-Job","page":"Quick Start","title":"Your First Scheduled Job","text":"","category":"section"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"Here's the minimal example to get you started:","category":"page"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"using Gears\n\n# Schedule a job to run every 200 milliseconds\nevery(200ms) do dt\n    println(\"Task executed at $(now(global_clock()))\")\nend\n\n# Run the scheduler for 1 second\nfor_next(1s) do\n    update!()\nend","category":"page"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"That's it! This will:","category":"page"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"Schedule a job to print a message every 200ms\nRun the scheduler for 1 second\nExecute the scheduled task 5 times","category":"page"},{"location":"quickstart/#What-Just-Happened?","page":"Quick Start","title":"What Just Happened?","text":"","category":"section"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"every(200ms) creates a timed job that runs every 200 milliseconds\nfor_next(1s) runs the scheduler for 1 second of simulated time\nupdate!() processes all scheduled jobs and advances time\nnow(global_clock()) gets the current time from the default clock","category":"page"},{"location":"quickstart/#Next-Steps","page":"Quick Start","title":"Next Steps","text":"","category":"section"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"Ready to learn more? Check out the Basic Scheduling tutorial to understand the fundamentals, or jump to any topic that interests you:","category":"page"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"Basic Scheduling - Learn job scheduling fundamentals\nClocks and Time - Understand time control\nJob Types - Explore different job triggers\nSchedulers - Configure job execution\nThreading - Run jobs in parallel","category":"page"},{"location":"quickstart/","page":"Quick Start","title":"Quick Start","text":"","category":"page"},{"location":"tutorials/clocks_and_time/#tutorial-clocks-time","page":"Clocks and Time","title":"Clocks and Time","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Time management is fundamental to Gears. If you've been following along the tutorials, you have already scheduled tasks at regular intervals. In this tutorial, we will cover how time is being managed and how you can control it for simulations.","category":"page"},{"location":"tutorials/clocks_and_time/#Time-Abstraction","page":"Clocks and Time","title":"Time Abstraction","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Gears abstracts time through Clocks. Clocks provide a unified interface for getting the current time, whether you're working with real system time or controllable simulation time. Under the hood, EnviornmentEngine will call the now function on the active clock to get the current time.","category":"page"},{"location":"tutorials/clocks_and_time/#Gears.now-tutorials-clocks_and_time","page":"Clocks and Time","title":"Gears.now","text":"now(clock::Clock)\n\nReturns the current time in the clock using Unitful to represent the unit of time.\n\n\n\n\n\n","category":"function"},{"location":"tutorials/clocks_and_time/#Clock-Types","page":"Clocks and Time","title":"Clock Types","text":"","category":"section"},{"location":"tutorials/clocks_and_time/#MachineClock-Real-System-Time","page":"Clocks and Time","title":"MachineClock - Real System Time","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"MachineClock uses your system's real time:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"using Gears\n\nclock = MachineClock()\n\nprintln(now(clock))  # Current system time, 0.0 seconds\n\nresume!(clock)\nsleep(1.0)\npause!(clock)\n\nprintln(now(clock))  # Current system time, 1.0 seconds","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"When created, the MachineClock is paused by default, and can be resumed and paused at any time. ","category":"page"},{"location":"tutorials/clocks_and_time/#Gears.MachineClock-tutorials-clocks_and_time","page":"Clocks and Time","title":"Gears.MachineClock","text":"MachineClock\n\nA clock that uses the system time. The time is represented in seconds. Supports pausing and resuming to decouple logical time from system time. The start_time, pause_start_time, and total_paused_time are all represented in seconds and are wall clock (unstretched) time. Whenever now is called, the time is stretched by the stretch_factor. This means that when the stretch_factor is greater than 1, the time will progress faster than the wall clock time.\n\nFields\n\nstart_time::T: The system time when the clock was created or last reset\npaused::Bool: Whether the clock is currently paused\ntotal_paused_time::T: Cumulative time spent paused\npause_start_time::Union{T, Nothing}: System time when current pause started (if any)\nstretch_factor::F: The factor by which to stretch the time\n\n\n\n\n\n","category":"type"},{"location":"tutorials/clocks_and_time/#Stretch-Factor","page":"Clocks and Time","title":"Stretch Factor","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"The MachineClock has a stretch factor, which is a factor by which the time is stretched. This is useful for building real-time applications, where the time is stretched to make the simulation run faster or slower than the real time. The stretch factor is set to 1.0 by default. If the stretch factor is greater than 1.0, the time will progress faster than the real time. For example, if the stretch factor is 2.0, the time will progress twice as fast as real time. You can set the stretch factor when creating the clock:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"using Gears\n\nclock = MachineClock(stretch_factor = 2.0)\nresume!(clock)\nsleep(1.0)\npause!(clock)\nprintln(now(clock))  # Current system time, 2.0 seconds","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"This is especially useful for debugging, and when you want to test if your agent has more/less computational resources available than on the machine you are running the simulation on.","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Use MachineClock when:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Building real-time applications\nYou want to sync with wall clock time\nRunning live simulations","category":"page"},{"location":"tutorials/clocks_and_time/#VirtualClock-Controllable-Time","page":"Clocks and Time","title":"VirtualClock - Controllable Time","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"VirtualClock gives you complete control over time. In the VirtualClock, you can advance time completely seperate from wall clock time:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"clock = VirtualClock()\n\n# Set initial time\nset_time!(clock, 0.0s)\n\n# Advance time manually\nadvance_time!(clock, 100ms)\nprintln(now(clock))  # 0.1 s\n\nadvance_time!(clock, 50ms)\nprintln(now(clock))  # 0.15 s","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Use VirtualClock when:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Building deterministic simulations\nYou need reproducible results\nDebugging timing issues\nTesting with specific time scenarios","category":"page"},{"location":"tutorials/clocks_and_time/#Time-Units","page":"Clocks and Time","title":"Time Units","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Gears uses Julia's Unitful.jl for time units:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"# All of these are equivalent\nevery(100ms) do dt; end\nevery(0.1s) do dt; end\nevery(100e-3s) do dt; end","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Common time units:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"ms - milliseconds\ns - seconds","category":"page"},{"location":"tutorials/clocks_and_time/#Integration-with-for_next()","page":"Clocks and Time","title":"Integration with for_next()","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"In the previous tutorials, we used for_next(duration) to advance time. However, when we are using a custom clock, we have fine-grained control over time advancement. This is reflected with the for_next(clock, duration) function.","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"clock = VirtualClock()\nfor_next(clock, 100ms) do\n    # Do your updates here\n    advance_time!(clock, 10ms)\nend","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"or:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"clock = MachineClock()\nfor_next(clock, 100ms) do\n    # Do your updates here\nend","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"For MachineClock, for_next will automatically resume the clock and pause it after the duration has passed. By using a custom clock, you get control over the time advancement in your simulations.","category":"page"},{"location":"tutorials/clocks_and_time/#Next-Steps","page":"Clocks and Time","title":"Next Steps","text":"","category":"section"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Now that you understand clocks and time control, explore:","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"Schedulers - Configure job execution behavior\nJob Types - Different ways to trigger jobs","category":"page"},{"location":"tutorials/clocks_and_time/","page":"Clocks and Time","title":"Clocks and Time","text":"","category":"page"},{"location":"tutorials/basic_scheduling/#tutorial-basic-scheduling","page":"Basic Scheduling","title":"Basic Scheduling","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Learn the fundamentals of job scheduling in Gears. This tutorial covers the core concepts you need to understand how jobs are scheduled and executed.","category":"page"},{"location":"tutorials/basic_scheduling/#The-Scheduling-Model","page":"Basic Scheduling","title":"The Scheduling Model","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Gears schedules jobs based on the current time as provided by the active clock and scheduler. Jobs are scheduled to run at specific times, whenever an event is triggered, or just as soon as possible. The scheduler determines when each job should execute according to its configuration.","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"note: Note\nBefore we dive into the basics of scheduling, let's cover the core concepts of clocks and schedulers. These concepts will be covered in more detail in the Clocks and Time and Schedulers tutorials. For now, it is enough to know that:A Scheduler is responsible for keeping a registry of jobs, and calling jobs when they are due.\nA Clock is responsible for providing the current time. A Scheduler uses a Clock to determine when jobs should be executed.","category":"page"},{"location":"tutorials/basic_scheduling/#Core-Functions","page":"Basic Scheduling","title":"Core Functions","text":"","category":"section"},{"location":"tutorials/basic_scheduling/#every()-Schedule-Jobs","page":"Basic Scheduling","title":"every() - Schedule Jobs","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"The every() function is your primary tool for scheduling jobs:","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"# Schedule a job every 100 milliseconds\nevery(100ms) do dt\n    println(\"Executed after $dt seconds\")\nend","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"The dt parameter represents the time elapsed since the last execution. Here, we have configured a job to run on a time interval, and the scheduler will execute the job every 100 milliseconds. A job that runs on a time interval is called a timed job and always takes a dt parameter, so the body can depend on the time elapsed since the last execution.","category":"page"},{"location":"tutorials/basic_scheduling/#for_next()-Run-the-Scheduler","page":"Basic Scheduling","title":"for_next() - Run the Scheduler","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Use for_next() to run the scheduler for a specific duration:","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"# Run the scheduler for 500 milliseconds\nfor_next(500ms) do\n    update!()\nend","category":"page"},{"location":"tutorials/basic_scheduling/#update!()-Process-Jobs","page":"Basic Scheduling","title":"update!() - Process Jobs","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"update!() advances time and executes all jobs that are due:","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"update!()  # Process all scheduled jobs","category":"page"},{"location":"tutorials/basic_scheduling/#A-Complete-Example","page":"Basic Scheduling","title":"A Complete Example","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Let's build a simple simulation that demonstrates basic scheduling:","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"using Gears\n\n# Schedule a sensor reading every 50ms\nevery(50ms) do dt\n    reading = rand() * 100\n    println(\"Sensor reading: $(round(reading, digits=2))\")\nend\n\n# Schedule a status report every 180ms\nevery(180ms) do dt\n    println(\"Status report at $(now(global_clock()))\")\nend\n\n# Run the simulation for 1 second\nfor_next(1.0s) do\n    update!()\nend","category":"page"},{"location":"tutorials/basic_scheduling/#Understanding-the-Output","page":"Basic Scheduling","title":"Understanding the Output","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Notice that:","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"The sensor runs every 50ms (4 times per 200ms)\nThe status report runs every 180ms\nBoth jobs run independently","category":"page"},{"location":"tutorials/basic_scheduling/#Key-Concepts","page":"Basic Scheduling","title":"Key Concepts","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Independent Jobs: Each every() call creates a separate job that runs independently\nSynchronous Execution: All jobs due at a given time are executed before time advances","category":"page"},{"location":"tutorials/basic_scheduling/#Next-Steps","page":"Basic Scheduling","title":"Next Steps","text":"","category":"section"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Now that you understand basic scheduling, you're ready to learn about:","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"Clocks and Time - Control time in your simulations\nSchedulers - Configure job execution behavior\nJob Types - Different ways to trigger jobs","category":"page"},{"location":"tutorials/basic_scheduling/","page":"Basic Scheduling","title":"Basic Scheduling","text":"","category":"page"},{"location":"user_guide/api_reference/#user-guide-api-reference","page":"API Reference","title":"API Reference","text":"","category":"section"},{"location":"user_guide/api_reference/#Gears.MachineClock","page":"API Reference","title":"Gears.MachineClock","text":"MachineClock\n\nA clock that uses the system time. The time is represented in seconds. Supports pausing and resuming to decouple logical time from system time. The start_time, pause_start_time, and total_paused_time are all represented in seconds and are wall clock (unstretched) time. Whenever now is called, the time is stretched by the stretch_factor. This means that when the stretch_factor is greater than 1, the time will progress faster than the wall clock time.\n\nFields\n\nstart_time::T: The system time when the clock was created or last reset\npaused::Bool: Whether the clock is currently paused\ntotal_paused_time::T: Cumulative time spent paused\npause_start_time::Union{T, Nothing}: System time when current pause started (if any)\nstretch_factor::F: The factor by which to stretch the time\n\n\n\n\n\n","category":"type"},{"location":"user_guide/api_reference/#Gears.TickedScheduler","page":"API Reference","title":"Gears.TickedScheduler","text":"TickedScheduler{C <: Clock, T} <: Scheduler\n\nA scheduler that processes jobs at regular tick intervals.\n\nFields\n\nclock::C: The clock providing time information\njobs::Vector{Job}: The jobs to be scheduled\nticker::Ticker{T}: The ticker that manages timing\n\n\n\n\n\n","category":"type"},{"location":"user_guide/api_reference/#Gears.TickedScheduler-Union{Tuple{T}, Tuple{Gears.Clock, T}} where T","page":"API Reference","title":"Gears.TickedScheduler","text":"TickedScheduler(clock::Clock, tick_period::T) where {T}\n\nCreate a new TickedScheduler with the specified clock and tick period.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.Ticker","page":"API Reference","title":"Gears.Ticker","text":"Ticker{T}\n\nA mutable struct that handles time accumulation and tick processing.\n\nFields\n\nperiod::T: The fixed tick period\nlast_tick_time::T: The time when the last tick was processed\naccumulated_lag::T: Unprocessed time since the last tick\n\n\n\n\n\n","category":"type"},{"location":"user_guide/api_reference/#Gears.Ticker-Union{Tuple{Unitful.Quantity{T, 𝐓}}, Tuple{T}} where T","page":"API Reference","title":"Gears.Ticker","text":"Ticker(period::Quantity{T, 𝐓}) where {T}\n\nCreate a new Ticker with the specified tick period.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.TimedJob","page":"API Reference","title":"Gears.TimedJob","text":"TimedJob{F, T}\n\nA job that executes at regular time intervals.\n\nFields\n\nf::F: The function to execute\nticker::Ticker{T}: The ticker that manages timing\n\n\n\n\n\n","category":"type"},{"location":"user_guide/api_reference/#Gears.TimedJob-Union{Tuple{T}, Tuple{Any, Unitful.Quantity{T, 𝐓}}} where T","page":"API Reference","title":"Gears.TimedJob","text":"TimedJob(f, period::Quantity{T, 𝐓}) where {T}\n\nCreate a new TimedJob with the specified function and tick period.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.VirtualClock","page":"API Reference","title":"Gears.VirtualClock","text":"VirtualClock\n\nA clock that uses virtual time for simulations. The time is represented in seconds.\n\nFields\n\ncurrent_time::T: The current time of the clock\n\nThis clock can be advanced with the advance_time! function.\n\n\n\n\n\n","category":"type"},{"location":"user_guide/api_reference/#Gears.advance_time!-Union{Tuple{T}, Tuple{VirtualClock{T}, Unitful.Quantity{<:Number, 𝐓}}} where T","page":"API Reference","title":"Gears.advance_time!","text":"advance_time!(clock::VirtualClock{T}, dt::Quantity{<:Number, 𝐓})\n\nAdvance the time of the clock by a given duration. Uses Unitful.jl for time units.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.advance_to!-Tuple{Gears.Ticker, Unitful.Quantity{<:Number, 𝐓}}","page":"API Reference","title":"Gears.advance_to!","text":"advance_to!(ticker::Ticker, absolute_time::Quantity{<:Number, 𝐓})\n\nAdvance the ticker to an absolute time, updating internal state accordingly.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.can_tick-Tuple{Gears.Ticker}","page":"API Reference","title":"Gears.can_tick","text":"can_tick(ticker::Ticker)\n\nCheck if the ticker has accumulated enough time to process a tick.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.consume_tick!-Tuple{Gears.Ticker}","page":"API Reference","title":"Gears.consume_tick!","text":"consume_tick!(ticker::Ticker)\n\nConsume one tick, reducing the accumulated lag by the tick period.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.global_clock-Tuple{}","page":"API Reference","title":"Gears.global_clock","text":"global_clock()\n\nReturns the global clock instance.\n\nNote: This function is type-unstable but the type instability is isolated by function barriers in the calling code.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.global_scheduler-Tuple{}","page":"API Reference","title":"Gears.global_scheduler","text":"global_scheduler()\n\nReturns the global scheduler instance.\n\nNote: This function is type-unstable but the type instability is isolated by function barriers in the calling code.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.now-Tuple{Gears.Clock}","page":"API Reference","title":"Gears.now","text":"now(clock::Clock)\n\nReturns the current time in the clock using Unitful to represent the unit of time.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.pause!-Tuple{MachineClock}","page":"API Reference","title":"Gears.pause!","text":"pause!(clock::MachineClock)\n\nPause the clock. While paused, logical time stops progressing.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.progress!-Tuple{Gears.Job, Unitful.Quantity{<:Number, 𝐓}}","page":"API Reference","title":"Gears.progress!","text":"progress!(job::Job, t::Quantity{<:Number, 𝐓})\n\nExecute the job with the current time. The job decides internally whether to perform work.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.progress!-Tuple{Gears.Ticker, Unitful.Quantity{<:Number, 𝐓}}","page":"API Reference","title":"Gears.progress!","text":"progress!(ticker::Ticker, delta_time::Quantity{<:Number, 𝐓})\n\nProgress the ticker by a delta time, updating internal state accordingly.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.progress!-Tuple{Gears.TimedJob, Unitful.Quantity{<:Number, 𝐓}}","page":"API Reference","title":"Gears.progress!","text":"progress!(job::TimedJob, dt::Quantity{<:Number, 𝐓})\n\nProgress the job by the specified time delta, executing the function for each available tick.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.reset!-Tuple{Gears.Ticker, Unitful.Quantity{<:Number, 𝐓}}","page":"API Reference","title":"Gears.reset!","text":"reset!(ticker::Ticker, time::Quantity{<:Number, 𝐓})\n\nReset the ticker to start at the specified time with no accumulated lag.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.reset_global_clock!-Tuple{}","page":"API Reference","title":"Gears.reset_global_clock!","text":"reset_global_clock!()\n\nResets the global clock to the default MachineClock instance.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.reset_global_scheduler!-Tuple{}","page":"API Reference","title":"Gears.reset_global_scheduler!","text":"reset_global_scheduler!()\n\nResets the global scheduler to the default TickedScheduler instance.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.resume!-Tuple{MachineClock}","page":"API Reference","title":"Gears.resume!","text":"resume!(clock::MachineClock)\n\nResume the clock. Logical time continues from where it was paused.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.schedule!-Tuple{Gears.Scheduler, Gears.Job}","page":"API Reference","title":"Gears.schedule!","text":"schedule!(scheduler::Scheduler, job::Job)\n\nRegister a job with the scheduler to run. Can be implemented for concrete types to define scheduling behavior for different schedulers and job types.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.schedule!-Tuple{TickedScheduler, Gears.Job}","page":"API Reference","title":"Gears.schedule!","text":"schedule!(scheduler::TickedScheduler, job::Job)\n\nSchedule a job to be executed by the scheduler.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.set_global_clock!-Tuple{Gears.Clock}","page":"API Reference","title":"Gears.set_global_clock!","text":"set_global_clock!(clock::Clock)\n\nSets the global clock to the specified instance.\n\nArguments\n\nclock::Clock: The clock instance to use globally\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.set_global_scheduler!-Tuple{Gears.Scheduler}","page":"API Reference","title":"Gears.set_global_scheduler!","text":"set_global_scheduler!(scheduler::Scheduler)\n\nSets the global scheduler to the specified instance.\n\nArguments\n\nscheduler::Scheduler: The scheduler instance to use globally\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.set_time!-Union{Tuple{T}, Tuple{VirtualClock{T}, Unitful.Quantity{<:Number, 𝐓}}} where T","page":"API Reference","title":"Gears.set_time!","text":"set_time!(clock::VirtualClock{T}, time::Quantity{<:Number, 𝐓})\n\nSet the time of the clock. Uses Unitful.jl for time units.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.update!-Tuple{Gears.Scheduler}","page":"API Reference","title":"Gears.update!","text":"update!(scheduler::Scheduler)\n\nUpdate the scheduler to the current time as provided with the associated clock. This distributes time to the scheduled jobs until virtual time has caught up with the current time provided by the clock (optionally also virtual).\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/#Gears.update!-Tuple{TickedScheduler}","page":"API Reference","title":"Gears.update!","text":"update!(scheduler::TickedScheduler)\n\nUpdate the scheduler by advancing to the current time and processing available ticks.\n\n\n\n\n\n","category":"method"},{"location":"user_guide/api_reference/","page":"API Reference","title":"API Reference","text":"","category":"page"},{"location":"#Gears","page":"Home","title":"Gears","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"A Julia package for scheduling tasks in simulation environments with precise timing control.","category":"page"},{"location":"#Quick-Start","page":"Home","title":"Quick Start","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"using Gears\n\n# Schedule a task every 200ms\nevery(200ms) do dt\n    println(\"Task executed at $(now(global_clock()))\")\nend\n\n# Run the scheduler for 1 second\nfor_next(1s) do\n    update!()\nend","category":"page"},{"location":"#Features","page":"Home","title":"Features","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Timed Jobs: Execute tasks at regular intervals\nASAP Jobs: Execute tasks as soon as possible  \nEvent Jobs: Execute tasks when data arrives on channels\nMultiple Clocks: Machine time or controllable virtual time\nFlexible Scheduling: Global or custom schedulers\nMulti-threading: Parallel job execution","category":"page"},{"location":"#Documentation","page":"Home","title":"Documentation","text":"","category":"section"},{"location":"#Getting-Started","page":"Home","title":"Getting Started","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Quick Start - Get up and running in 5 minutes","category":"page"},{"location":"#Tutorials","page":"Home","title":"Tutorials","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Tutorials - Step-by-step learning guide\nBasic Scheduling - Learn job scheduling fundamentals\nClocks and Time - Understand time control\nJob Types - Explore different job triggers\nSchedulers - Configure job execution\nThreading - Run jobs in parallel","category":"page"},{"location":"#User-Guide","page":"Home","title":"User Guide","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"User Guide - Complete reference documentation\nAPI Reference - Function and type documentation\nSharp Bits - Learn about sharp bits","category":"page"},{"location":"#Architecture","page":"Home","title":"Architecture","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Architecture - Implementation details and design","category":"page"},{"location":"#Index","page":"Home","title":"Index","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"","category":"page"},{"location":"","page":"Home","title":"Home","text":"","category":"page"}]
